/* BTTabs — tab molecule (Figma 1:53 / Base/TabItem 434:5262)
 *
 * Variants:  segmented · line
 * Animation: sliding indicator (not opacity/border toggling)
 * Scrollable: overflow-x auto + center-on-active
 *
 * Architecture:
 *   .bt-tabs                    root — position:relative for absolute indicator
 *   .bt-tabs--segmented         pill-style tray
 *   .bt-tabs--line              underline-style
 *   .bt-tabs--scrollable        horizontal scroll, fills parent width
 *   .bt-tabs--ready             enables CSS transition (added after first paint)
 *   .bt-tabs__indicator         sliding pill / underline — absolutely positioned
 *   .bt-tabs__item              individual tab button — z-index:1 (above indicator)
 *   .bt-tabs__item--active      active text color
 *   .bt-tabs__icon              icon wrapper slot
 */

/* ── Container ───────────────────────────────────────────────────────────── */

.bt-tabs {
  display: inline-flex;
  align-items: center;
  position: relative;  /* anchor for absolute indicator */
}

/* Scrollable: fills parent, allows horizontal overflow */
.bt-tabs--scrollable {
  display: flex;
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  /* Thin scrollbar — visible so desktop users know it's scrollable */
  scrollbar-width: thin;                    /* Firefox */
  scrollbar-color: transparent transparent; /* hidden at rest, shown on hover */
}
/* Chrome/Safari: 3px scrollbar, hidden at rest */
.bt-tabs--scrollable::-webkit-scrollbar {
  height: 3px;
}
.bt-tabs--scrollable::-webkit-scrollbar-track {
  background: transparent;
}
.bt-tabs--scrollable::-webkit-scrollbar-thumb {
  background: transparent;
  border-radius: 4px;
}
/* Reveal scrollbar on hover */
.bt-tabs--scrollable:hover {
  scrollbar-color: rgb(0 0 0 / 0.2) transparent;
}
.bt-tabs--scrollable:hover::-webkit-scrollbar-thumb {
  background: rgb(0 0 0 / 0.2);
}

/* Segmented: gray tray, 4px padding, radius.md, height 40px */
.bt-tabs--segmented {
  background: var(--bg-secondary);
  border-radius: var(--radius-md);
  padding: 4px;
  gap: 0;
  height: 40px;
}

/* Line: no tray, 4px gap between items */
.bt-tabs--line {
  gap: 4px;
  background: none;
}

/* ── Sliding indicator ───────────────────────────────────────────────────── */

.bt-tabs__indicator {
  position: absolute;
  pointer-events: none;
  z-index: 0;
  /* transition enabled only after first paint (.bt-tabs--ready) */
}

.bt-tabs--ready .bt-tabs__indicator {
  transition:
    left  0.22s cubic-bezier(0.4, 0, 0.2, 1),
    width 0.22s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Segmented: filled primary pill behind the label */
.bt-tabs--segmented .bt-tabs__indicator {
  top:    4px;   /* = container padding-top */
  height: 32px;
  background: var(--color-brand-primary);
  border-radius: var(--radius-sm);
}

/* Line: 2px primary underline at the bottom */
.bt-tabs--line .bt-tabs__indicator {
  bottom: 0;
  height: 2px;
  background: var(--color-brand-primary);
}

/* ── Tab item ────────────────────────────────────────────────────────────── */

.bt-tabs__item {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  height: 32px;
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: none;
  background: none;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  font-family: var(--typography-font-family-sans, 'Geist', sans-serif);
  font-size: 14px;
  font-weight: 500;
  line-height: 16px;
  letter-spacing: 0;
  color: var(--text-secondary);
  transition: color 0.22s cubic-bezier(0.4, 0, 0.2, 1);
  flex-shrink: 0;
  /* above the absolute indicator */
  position: relative;
  z-index: 1;
}

.bt-tabs__item:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
  z-index: 2;
}

.bt-tabs__item:disabled,
.bt-tabs__item[aria-disabled='true'] {
  opacity: 0.4;
  cursor: not-allowed;
}

/* ── Segmented active / hover ────────────────────────────────────────────── */

/* Active text color — background is the sliding indicator */
.bt-tabs--segmented .bt-tabs__item--active {
  color: var(--text-inverse);
}

.bt-tabs--segmented .bt-tabs__item:not(.bt-tabs__item--active):not(:disabled):hover {
  background: rgb(0 0 0 / 0.05);
  border-radius: var(--radius-sm);
}

/* ── Line active / hover ─────────────────────────────────────────────────── */

.bt-tabs--line .bt-tabs__item--active {
  color: var(--color-brand-primary);
}

.bt-tabs--line .bt-tabs__item:not(.bt-tabs__item--active):not(:disabled):hover {
  color: var(--text-secondary);
  opacity: 0.7;
}

/* ── Icon slot ───────────────────────────────────────────────────────────── */

.bt-tabs__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

/**
 * BTTabs — tab molecule (Figma 1:53 / Base/TabItem 434:5262).
 *
 * Two variants: 'segmented' (pill tray) · 'line' (underline).
 * Sliding indicator: absolutely-positioned div that animates left+width
 * instead of toggling classes — smooth slide on every tab change.
 * scrollable: overflow-x auto + centers the active tab on selection.
 *
 * @example
 * ```tsx
 * const [active, setActive] = useState(0);
 *
 * // Segmented
 * <BTTabs
 *   variant="segmented"
 *   tabs={[{ label: 'Overview' }, { label: 'Details' }, { label: 'History' }]}
 *   activeIndex={active}
 *   onActiveIndexChange={setActive}
 * />
 *
 * // Scrollable line
 * <BTTabs
 *   variant="line"
 *   scrollable
 *   tabs={manyTabs}
 *   activeIndex={active}
 *   onActiveIndexChange={setActive}
 * />
 * ```
 */
import { useCallback, useEffect, useRef, useState } from 'react';
import './BTTabs.css';
import type { BTTabsProps } from './BTTabs.types';

export interface BTTabsReactProps extends BTTabsProps {
  /** Called when the user selects a tab. Receives the new active index. */
  onActiveIndexChange?: (index: number) => void;
  /** Leading icon per tab index (render prop). */
  leadingIcon?: (index: number) => React.ReactNode;
  /** Trailing icon per tab index (render prop). */
  trailingIcon?: (index: number) => React.ReactNode;
}

export function BTTabs({
  variant = 'segmented',
  tabs,
  activeIndex = 0,
  scrollable = false,
  onActiveIndexChange,
  leadingIcon,
  trailingIcon,
  className,
}: BTTabsReactProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const buttonRefs = useRef<(HTMLButtonElement | null)[]>([]);

  // Sliding indicator geometry
  const [indicator, setIndicator] = useState({ left: 0, width: 0 });
  // Enables CSS transition only after the first paint (avoids slide-from-zero on mount)
  const [isReady, setIsReady] = useState(false);

  const updateIndicator = useCallback(
    (ready: boolean) => {
      const btn = buttonRefs.current[activeIndex];
      const container = containerRef.current;
      if (!btn || !container) return;

      setIndicator({ left: btn.offsetLeft, width: btn.offsetWidth });

      if (scrollable) {
        const center = btn.offsetLeft + btn.offsetWidth / 2;
        container.scrollTo({
          left: center - container.offsetWidth / 2,
          behavior: ready ? 'smooth' : 'instant',
        });
      }
    },
    [activeIndex, scrollable],
  );

  // First mount: position indicator without transition, then enable transition
  useEffect(() => {
    // rAF ensures layout is complete before we read offsetLeft
    const id = requestAnimationFrame(() => {
      updateIndicator(false);
      requestAnimationFrame(() => setIsReady(true));
    });
    return () => cancelAnimationFrame(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Active tab changes: slide indicator + center scroll
  useEffect(() => {
    if (!isReady) return;
    updateIndicator(true);
  }, [activeIndex, isReady, updateIndicator]);

  const handleClick = useCallback(
    (index: number, disabled?: boolean) => {
      if (disabled) return;
      onActiveIndexChange?.(index);
    },
    [onActiveIndexChange],
  );

  const rootClass = [
    'bt-tabs',
    `bt-tabs--${variant}`,
    scrollable ? 'bt-tabs--scrollable' : '',
    isReady ? 'bt-tabs--ready' : '',
    className ?? '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={rootClass} role="tablist" ref={containerRef}>
      {/* Sliding indicator — behind tab labels (z-index 0) */}
      <div
        className="bt-tabs__indicator"
        style={{ left: indicator.left, width: indicator.width }}
        aria-hidden
      />

      {tabs.map((tab, i) => (
        <button
          key={i}
          role="tab"
          ref={(el) => { buttonRefs.current[i] = el; }}
          className={[
            'bt-tabs__item',
            i === activeIndex ? 'bt-tabs__item--active' : '',
          ]
            .filter(Boolean)
            .join(' ')}
          aria-selected={i === activeIndex}
          aria-disabled={tab.disabled || undefined}
          disabled={tab.disabled}
          tabIndex={i === activeIndex ? 0 : -1}
          onClick={() => handleClick(i, tab.disabled)}
        >
          {leadingIcon && (
            <span className="bt-tabs__icon">{leadingIcon(i)}</span>
          )}
          {tab.label}
          {trailingIcon && (
            <span className="bt-tabs__icon">{trailingIcon(i)}</span>
          )}
        </button>
      ))}
    </div>
  );
}

BTTabs.displayName = 'BTTabs';

// BTTabs types — Figma source: node 1:53 · Base/TabItem 434:5262

/** Visual style of the tab strip. */
export type BTTabsVariant = 'segmented' | 'line';

/** Data for a single tab. */
export interface BTTabItem {
  /** Label text displayed in the tab. */
  label: string;
  /** Whether this tab is not interactive. @default false */
  disabled?: boolean;
}

export interface BTTabsProps {
  /**
   * Visual variant.
   * - `'segmented'` — pill-style tray, active tab has filled primary background.
   * - `'line'`      — flat row, active tab has primary underline border.
   * @default 'segmented'
   */
  variant?: BTTabsVariant;
  /** Ordered list of tab descriptors. */
  tabs: BTTabItem[];
  /**
   * Zero-based index of the currently active tab.
   * Controlled via `v-model:activeIndex`.
   */
  activeIndex?: number;
  /**
   * When `true`, the tab strip becomes horizontally scrollable and
   * auto-scrolls to center the active tab on each selection.
   * Useful when there are many tabs and the container is narrow.
   * @default false
   */
  scrollable?: boolean;
  /** Additional CSS class names on the root element. */
  className?: string;
}
